  1→/**
  2→ * BrowserTab — native Electron BrowserView for one browser tab.
  3→ *
  4→ * Architecture: Renders a placeholder <div> and measures its bounds via
  5→ * ResizeObserver. Tells the main process to create/position a native BrowserView there.
  6→ * Unlike iframes, native BrowserViews bypass X-Frame-Options so any URL loads.
  7→ *
  8→ * All tabs stack via CSS Grid ([grid-area:1/1]) in the parent container.
  9→ * The native BrowserView floats above the DOM; overlays only show when view is hidden.
 10→ *
 11→ * Communication channels (each concern gets its own reliable path):
 12→ *   - IPC events: page-load, title-changed, url-change (push from Electron webContents)
 13→ *   - executeJavaScript: console drain + inspect event drain (pull from React)
 14→ *
 15→ * SPA navigation: pushState/replaceState patches in the init script fire
 16→ * browser:url-change events so the URL bar stays current.
 17→ */
 18→
 19→import {
 20→  useRef,
 21→  useState,
 22→  useEffect,
 23→  useLayoutEffect,
 24→  useCallback,
 25→  useImperativeHandle,
 26→  forwardRef,
 27→} from "react";
 28→import { match } from "ts-pattern";
 29→import { Button } from "@/components/ui/button";
 30→import { AlertCircle, Loader2, Globe } from "lucide-react";
 31→import { native } from "@/platform";
 32→import { BROWSER_PAGE_LOAD, BROWSER_TITLE_CHANGED, BROWSER_URL_CHANGE } from "@shared/events";
 33→import { getErrorMessage } from "@shared/lib/errors";
 34→import type { BrowserTabState, BrowserTabHandle, ConsoleLog, ElementSelectedEvent } from "../types";
 35→import { deriveTitleFromUrl } from "../types";
 36→import {
 37→  INSPECT_MODE_SETUP,
 38→  INSPECT_MODE_ENABLE,
 39→  INSPECT_MODE_DISABLE,
 40→  INSPECT_MODE_DRAIN_EVENTS,
 41→  INSPECT_MODE_VERIFY,
 42→} from "../automation/inspect-mode";
 43→import { VISUAL_EFFECTS_SETUP } from "../automation/visual-effects";
 44→
 45→/** How often to drain console logs from the webview (ms) */
 46→const CONSOLE_DRAIN_INTERVAL_MS = 1500;
 47→
 48→interface BrowserTabProps {
 49→  tab: BrowserTabState;
 50→  /** Update tab state in the parent — (tabId, updates) */
 51→  onUpdateTab: (tabId: string, updates: Partial<BrowserTabState>) => void;
 52→  /** Add a log line to the tab's console — (tabId, level, message) */
 53→  onAddLog: (tabId: string, level: ConsoleLog["level"], message: string) => void;
 54→  /** Whether this tab is the active (visible) tab */
 55→  visible: boolean;
 56→  /** Callback when user selects an element in inspect mode */
 57→  onElementSelected?: (tabId: string, event: ElementSelectedEvent) => void;
 58→  /** Which Electron window to create child BrowserViews in. Defaults to "main". */
 59→  windowLabel?: string;
 60→  /** When true, the browser container is constrained to mobile width (390px).
 61→   *  Used to trigger a bounds sync — mx-auto centering shifts x-offset
 62→   *  and ResizeObserver may not catch position-only changes. */
 63→  mobileView?: boolean;
 64→}
 65→
 66→export const BrowserTab = forwardRef<BrowserTabHandle, BrowserTabProps>(function BrowserTab(
 67→  { tab, onUpdateTab, onAddLog, visible, onElementSelected, windowLabel, mobileView },
 68→  ref
 69→) {
 70→  const placeholderRef = useRef<HTMLDivElement>(null);
 71→  // Ref = source of truth for imperative callbacks (always fresh)
 72→  const webviewCreatedRef = useRef(false);
 73→  // State = triggers effects when webview is ready
 74→  const [webviewReady, setWebviewReady] = useState(false);
 75→  // Track whether first page load completed (show overlay only during initial load)
 76→  const [hasLoaded, setHasLoaded] = useState(false);
 77→  // Brief "completing" state for loading bar finish animation (fill → fade)
 78→  const [completingLoad, setCompletingLoad] = useState(false);
 79→  const completingTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
 80→  // Guard against unmount during async webview creation
 81→  const mountedRef = useRef(true);
 82→  // Debounce bounds sync to one per animation frame
 83→  const rafRef = useRef(0);
 84→  // Track whether automation scripts (inspect mode + visual effects) have been injected
 85→  const automationInjectedRef = useRef(false);
 86→  // Ref to latest tab state — used in event handlers to read current history
 87→  const tabRef = useRef(tab);
 88→  tabRef.current = tab;
 89→  // Guard: suppress history push during back/forward navigation
 90→  // (did-navigate fires for loadURL too, which would double-push)
 91→  const suppressHistoryPushRef = useRef(false);
 92→  // Stable ref for onElementSelected callback (used by the inspect drain loop)
 93→  const onElementSelectedRef = useRef(onElementSelected);
 94→  onElementSelectedRef.current = onElementSelected;
 95→  // Track previous mobileView value to detect actual toggles (vs initial mount)
 96→  const prevMobileViewRef = useRef(mobileView);
 97→
 98→  const tabId = tab.id;
 99→  const webviewLabel = tab.webviewLabel;
100→
101→  // --- Unmount guard ---
102→  useEffect(() => {
103→    mountedRef.current = true;
104→    return () => {
105→      mountedRef.current = false;
106→      cancelAnimationFrame(rafRef.current);
107→      if (completingTimerRef.current) clearTimeout(completingTimerRef.current);
108→    };
109→  }, []);
110→
111→  // --- Create webview (lazy, on first navigation) ---
112→
113→  const createWebviewIfNeeded = useCallback(
114→    async (url: string) => {
115→      if (webviewCreatedRef.current) return;
116→
117→      // Set flag SYNCHRONOUSLY before await to prevent the auto-navigate
118→      // effect from re-firing during the async gap (onUpdateTab triggers
119→      // re-render → effect re-runs → ref still false → duplicate create).
120→      webviewCreatedRef.current = true;
121→
122→      const el = placeholderRef.current;
123→      if (!el) {
124→        webviewCreatedRef.current = false;
125→        return;
126→      }
127→
128→      const rect = el.getBoundingClientRect();
129→      try {
130→        await native.browserViews.create({
131→          label: webviewLabel,
132→          url,
133→          x: rect.x,
134→          y: rect.y,
135→          width: Math.max(rect.width, 100),
136→          height: Math.max(rect.height, 100),
137→          windowLabel: windowLabel ?? "main",
