394→      var b = window.__DEUS_LOGS__ || [];
395→      window.__DEUS_LOGS__ = [];
396→      return JSON.stringify(b);
397→    })()`;
398→
399→    // Track consecutive failures for diagnostic logging
400→    let consoleDrainFails = 0;
401→    // Guard against overlapping async drains — if invoke() takes longer than
402→    // the interval, skip until the previous call completes.
403→    let inFlight = false;
404→
405→    const interval = setInterval(async () => {
406→      if (inFlight) return;
407→      inFlight = true;
408→      try {
409→        const result = await native.browserViews.evaluateWithResult(
410→          webviewLabel,
411→          CONSOLE_DRAIN_JS,
412→          2000
413→        );
414→        // Reset on success
415→        consoleDrainFails = 0;
416→
417→        if (!result || result === "[]" || result === "undefined") return;
418→
419→        let logs: Array<{ l: string; m: string; t: number }>;
420→        try {
421→          logs = JSON.parse(result);
422→        } catch (parseErr) {
423→          console.error(
424→            "[BrowserTab] console drain: JSON.parse failed",
425→            parseErr,
426→            "raw:",
427→            result.slice(0, 200)
428→          );
429→          return;
430→        }
431→        for (const log of logs) {
432→          const level = match(log.l)
433→            .with("warn", () => "warn" as const)
434→            .with("error", () => "error" as const)
435→            .with("debug", () => "debug" as const)
436→            .otherwise(() => "info" as const);
437→          onAddLog(tabId, level, log.m);
438→        }
439→      } catch (err) {
440→        consoleDrainFails++;
441→        if (consoleDrainFails <= 3 || consoleDrainFails % 50 === 0) {
442→          console.warn(
443→            `[BrowserTab] console drain failed (${consoleDrainFails}x):`,
444→            getErrorMessage(err)
445→          );
446→        }
447→      } finally {
448→        inFlight = false;
449→      }
450→    }, CONSOLE_DRAIN_INTERVAL_MS);
451→
452→    return () => clearInterval(interval);
