736→      {/* Loading overlay: only during initial page load (webview hidden) */}
737→      {visible && tab.loading && !hasLoaded && (
738→        <div className="vibrancy-bg absolute inset-0 flex items-center justify-center">
739→          <Loader2 className="text-primary h-8 w-8 animate-spin" />
740→        </div>
741→      )}
