743→      {/* Error overlay: only if initial load failed */}
744→      {visible && tab.error && !hasLoaded && (
745→        <div className="vibrancy-bg absolute inset-0 flex items-center justify-center">
746→          <div className="max-w-sm p-8 text-center">
747→            <div className="bg-destructive/10 mx-auto mb-4 flex h-10 w-10 items-center justify-center rounded-xl">
