  1→// agent-server/agents/deus-tools/browser.ts
  2→// Browser automation tools powered by agent-browser CLI.
  3→// Each tool executes agent-browser commands via CDP (Chrome DevTools Protocol)
  4→// in a headed Chrome window. The daemon auto-starts on first use per session.
  5→//
  6→// Snapshot file-based fallback:
  7→// When a page snapshot exceeds SNAPSHOT_SIZE_THRESHOLD, the full snapshot
  8→// is written to ~/.deus/browser-logs/ and only a preview (first N lines)
  9→// is returned to the AI context. The AI can read the full file if needed.
 10→
 11→import { tool } from "@anthropic-ai/claude-agent-sdk";
 12→import type { SdkMcpToolDefinition } from "@anthropic-ai/claude-agent-sdk";
 13→import { z } from "zod";
 14→import { writeFileSync, mkdirSync, existsSync, readFileSync, unlinkSync } from "fs";
 15→import { join } from "path";
 16→import { homedir, tmpdir } from "os";
 17→import { getErrorMessage } from "@shared/lib/errors";
 18→import { execAgentBrowser, execWithSnapshot, getSnapshot } from "./agent-browser-client";
 19→
 20→// ============================================================================
 21→// Snapshot file-based fallback constants
 22→// ============================================================================
 23→
 24→const SNAPSHOT_SIZE_THRESHOLD = 25 * 1024; // 25 KB for action tools
 25→const SNAPSHOT_SIZE_THRESHOLD_LARGE = 200 * 1024; // 200 KB for BrowserSnapshot
 26→const PREVIEW_LINE_COUNT = 50;
 27→const BROWSER_LOGS_DIR = join(homedir(), ".deus", "browser-logs");
 28→
 29→/**
 30→ * Format a snapshot response with file-based fallback for large snapshots.
 31→ */
 32→function formatSnapshotResponse(
 33→  action: string,
 34→  snapshot: string | undefined,
 35→  pageUrl?: string,
 36→  pageTitle?: string,
 37→  detailLines?: string[],
 38→  sizeThreshold: number = SNAPSHOT_SIZE_THRESHOLD
 39→): string {
 40→  const sections: string[] = [];
 41→
 42→  sections.push(`### Action: ${action}`);
 43→  if (detailLines && detailLines.length > 0) {
 44→    for (const line of detailLines) {
 45→      sections.push(`- ${line}`);
 46→    }
 47→  }
 48→
 49→  sections.push("");
 50→  sections.push("### Page state");
 51→  if (pageUrl) sections.push(`- Page URL: ${pageUrl}`);
 52→  if (pageTitle) sections.push(`- Page Title: ${pageTitle}`);
 53→
 54→  if (!snapshot) {
 55→    sections.push("- Page Snapshot: (not available)");
 56→    return sections.join("\n");
 57→  }
 58→
 59→  const snapshotBytes = Buffer.byteLength(snapshot, "utf-8");
 60→  const snapshotLines = snapshot.split("\n");
 61→
 62→  if (snapshotBytes <= sizeThreshold) {
 63→    sections.push(`- Page Snapshot (${snapshotLines.length} lines)`);
 64→    sections.push("");
 65→    sections.push(snapshot);
 66→  } else {
 67→    let filePath: string | null = null;
 68→    try {
 69→      if (!existsSync(BROWSER_LOGS_DIR)) {
 70→        mkdirSync(BROWSER_LOGS_DIR, { recursive: true });
 71→      }
 72→      const timestamp = new Date().toISOString().replace(/[:.]/g, "-");
 73→      const filename = `snapshot-${timestamp}.log`;
 74→      filePath = join(BROWSER_LOGS_DIR, filename);
 75→      writeFileSync(filePath, snapshot, "utf-8");
 76→    } catch (err: unknown) {
 77→      console.warn(`[browser] Failed to write snapshot file: ${getErrorMessage(err)}`);
 78→    }
 79→
 80→    if (filePath) {
 81→      sections.push(
 82→        `- Page Snapshot: Large snapshot (${snapshotBytes} bytes, ${snapshotLines.length} lines) written to file`
 83→      );
 84→      sections.push(`- Snapshot File: ${filePath}`);
 85→      sections.push(`- Preview (first ${PREVIEW_LINE_COUNT} lines):`);
 86→      sections.push("");
 87→      sections.push(snapshotLines.slice(0, PREVIEW_LINE_COUNT).join("\n"));
 88→      const remaining = snapshotLines.length - PREVIEW_LINE_COUNT;
 89→      if (remaining > 0) {
 90→        sections.push("");
 91→        sections.push(`... (${remaining} more lines in file)`);
 92→      }
 93→    } else {
 94→      const truncated = snapshotLines.slice(0, PREVIEW_LINE_COUNT).join("\n");
 95→      sections.push(
 96→        `- Page Snapshot: Large snapshot (${snapshotBytes} bytes, ${snapshotLines.length} lines) — truncated inline`
 97→      );
 98→      sections.push("");
 99→      sections.push(truncated);
100→      const remaining = snapshotLines.length - PREVIEW_LINE_COUNT;
101→      if (remaining > 0) {
102→        sections.push("");
103→        sections.push(`... (${remaining} more lines truncated)`);
104→      }
105→    }
106→  }
107→
108→  return sections.join("\n");
109→}
