754→          const requests = (result.data?.requests as string) || JSON.stringify(result.data);
755→
756→          if (!requests || requests === "[]" || requests === "null") {
757→            return {
758→              content: [{ type: "text", text: "No network requests captured." }],
759→            };
760→          }
761→
762→          return {
763→            content: [{ type: "text", text: `Network requests:\n${requests}` }],
764→          };
765→        } catch (err: unknown) {
766→          return {
767→            content: [{ type: "text", text: `Browser not available: ${getErrorMessage(err)}` }],
768→          };
769→        }
770→      }
771→    ),
772→
773→    // ====================================================================
774→    // BrowserScroll
775→    // ====================================================================
776→    tool(
777→      "BrowserScroll",
778→      `Scroll the page in a direction, or scroll a specific element into view.
779→
780→Two modes:
781→- **Direction scroll**: Scroll up/down/left/right by a pixel amount (default 600px)
782→- **Element scroll**: Provide a ref to scroll that element into view
783→
784→Returns a fresh accessibility snapshot after scrolling.`,
785→      {
786→        direction: z
787→          .enum(["up", "down", "left", "right"])
788→          .optional()
789→          .describe("Scroll direction. Default: 'down'. Ignored when ref is provided."),
790→        amount: z
791→          .number()
792→          .optional()
793→          .describe("Pixels to scroll (default 600). Ignored when ref is provided."),
794→        ref: z
795→          .string()
796→          .optional()
797→          .describe("Element ref to scroll into view. If provided, direction/amount are ignored."),
798→      },
799→      async (args) => {
800→        console.log(
801→          `[browser] BrowserScroll invoked for session ${sessionId}: dir=${args.direction} ref=${args.ref}`
802→        );
803→
804→        try {
805→          let scrollArgs: string[];
806→          if (args.ref) {
807→            // Scroll element into view
808→            scrollArgs = ["scroll", "--to", args.ref];
809→          } else {
810→            const dir = args.direction ?? "down";
811→            const amount = args.amount ?? 600;
812→            scrollArgs = ["scroll", dir, String(amount)];
813→          }
814→
815→          const response = await execWithSnapshot(sessionId, scrollArgs);
816→
817→          if (response.error) {
818→            return {
819→              content: [{ type: "text", text: `Scroll failed: ${response.error}` }],
820→            };
821→          }
822→
823→          const detailLines: string[] = [];
824→          if (args.ref) {
825→            detailLines.push(`Scrolled element into view: ${args.ref}`);
826→          } else {
827→            detailLines.push(`Scrolled ${args.direction ?? "down"} by ${args.amount ?? 600}px`);
828→          }
829→
830→          const text = formatSnapshotResponse(
831→            "scroll",
832→            response.snapshot,
833→            response.url,
834→            response.title,
835→            detailLines
836→          );
837→
838→          return { content: [{ type: "text", text }] };
839→        } catch (err: unknown) {
840→          return {
841→            content: [{ type: "text", text: `Browser not available: ${getErrorMessage(err)}` }],
842→          };
843→        }
844→      }
845→    ),
846→  ];
847→}
