  1→// Query protocol — WebSocket wire format for the cloud relay.
  2→// All frame types prefixed with "q:" so they route cleanly in the ws.service dispatcher.
  3→//
  4→// Domain constants (QUERY_RESOURCES, MUTATION_NAMES, COMMAND_NAMES, PROTOCOL_EVENTS)
  5→// live in shared/events.ts — the single source of truth for all app events
  6→// and resources. This file only defines the wire format that carries them.
  7→
  8→import type {
  9→  QueryResource,
 10→  RequestResource,
 11→  MutationName,
 12→  CommandName,
 13→  ProtocolEvent,
 14→} from "../events";
 15→
 16→// Re-export so existing `import { QueryResource } from "query-protocol"` still works.
 17→export type { QueryResource, RequestResource, MutationName, CommandName, ProtocolEvent };
 18→export {
 19→  QUERY_RESOURCES,
 20→  REQUEST_RESOURCES,
 21→  MUTATION_NAMES,
 22→  COMMAND_NAMES,
 23→  PROTOCOL_EVENTS,
 24→} from "../events";
 25→
 26→// ---- Client → Server Frames ----
 27→
 28→/** Client requests data (one-shot). Accepts both subscribable and request-only resources. */
 29→export interface QRequestFrame {
 30→  type: "q:request";
 31→  id: string;
 32→  resource: RequestResource;
 33→  params?: Record<string, unknown>;
 34→}
 35→
 36→/** Client subscribes to live updates for a resource. */
 37→export interface QSubscribeFrame {
 38→  type: "q:subscribe";
 39→  id: string;
 40→  resource: QueryResource;
 41→  params?: Record<string, unknown>;
 42→}
 43→
 44→/** Client unsubscribes by subscription ID (no resource/params needed). */
 45→export interface QUnsubscribeFrame {
 46→  type: "q:unsubscribe";
 47→  id: string;
 48→}
 49→
 50→/** Client requests a mutation. Field is `action`, not `mutation`. */
 51→export interface QMutateFrame {
 52→  type: "q:mutate";
 53→  id: string;
 54→  action: MutationName;
 55→  params: Record<string, unknown>;
 56→}
 57→
 58→/** Client sends an async command (e.g. sendMessage, stopSession). */
 59→export interface QCommandFrame {
 60→  type: "q:command";
 61→  id: string;
 62→  command: CommandName;
 63→  params: Record<string, unknown>;
 64→}
 65→
 66→/** Client responds to a tool relay request (q:event tool:request → q:tool_response). */
 67→export interface QToolResponseSuccessFrame {
 68→  type: "q:tool_response";
 69→  requestId: string;
 70→  result: unknown;
 71→  error?: never;
 72→}
 73→
 74→export interface QToolResponseErrorFrame {
 75→  type: "q:tool_response";
 76→  requestId: string;
 77→  error: string;
 78→  result?: never;
 79→}
 80→
 81→export type QToolResponseFrame = QToolResponseSuccessFrame | QToolResponseErrorFrame;
 82→
 83→/** All frames a client can send. */
 84→export type QClientFrame =
 85→  | QRequestFrame
 86→  | QSubscribeFrame
 87→  | QUnsubscribeFrame
 88→  | QMutateFrame
 89→  | QCommandFrame
 90→  | QToolResponseFrame;
 91→
 92→// ---- Server → Client Frames ----
 93→
 94→/** Server returns data for a one-shot request. */
 95→export interface QResponseFrame {
 96→  type: "q:response";
 97→  id: string;
 98→  data: unknown;
 99→}
100→

100→
101→/** Server pushes a full snapshot to a subscriber (keyed by subscription ID). */
102→export interface QSnapshotFrame {
103→  type: "q:snapshot";
104→  id: string;
105→  data: unknown;
106→  cursor?: number;
107→}
108→
109→/** Server pushes incremental update (keyed by subscription ID). */
110→export interface QDeltaFrame {
111→  type: "q:delta";
112→  id: string;
113→  upserted?: unknown[];
114→  removed?: string[];
115→  cursor?: number;
116→}
117→
118→/** Server returns mutation result. Uses `success`, not `ok`. */
119→export interface QMutateResultFrame {
120→  type: "q:mutate_result";
121→  id: string;
122→  success: boolean;
123→  data?: unknown;
124→  error?: string;
125→}
126→
127→/** Server tells clients to refetch stale resources. */
128→export interface QInvalidateFrame {
129→  type: "q:invalidate";
130→  resources: QueryResource[];
131→}
132→
133→/** Server acknowledges an async command. */
134→export interface QCommandAckFrame {
135→  type: "q:command_ack";
136→  id: string;
137→  accepted: boolean;
138→  commandId?: string;
139→  error?: string;
140→}
141→
142→/** Server pushes an ephemeral event (no subscription needed). */
143→export interface QEventFrame {
144→  type: "q:event";
145→  event: ProtocolEvent;
146→  data: unknown;
147→}
148→
149→/** Server error for a specific request. */
150→export interface QErrorFrame {
151→  type: "q:error";
152→  id: string;
153→  code: string;
154→  message: string;
155→}
156→
157→/** All frames a server can send. */
158→export type QServerFrame =
159→  | QResponseFrame
160→  | QSnapshotFrame
161→  | QDeltaFrame
162→  | QMutateResultFrame
163→  | QCommandAckFrame
164→  | QEventFrame
165→  | QInvalidateFrame
166→  | QErrorFrame;
167→
168→// ---- Tool Relay Event Payload ----
169→
170→/** Payload shape for q:event with event: "tool:request".
171→ *  Sent by the backend when relaying a tool request from the agent to the frontend.
172→ *  Derived from the canonical ToolRequestEvent (shared/agent-events.ts) minus the
173→ *  discriminator field — the WS frame wraps this in q:event, not as a standalone event. */
174→export type ToolRequestEventData = Omit<import("../agent-events").ToolRequestEvent, "type">;
175→

  1→// src/shared/hooks/useWsToolRequest.ts
  2→//
  3→// Shared hook that listens for tool:request events arriving via the WebSocket
  4→// q:event channel. Dispatches to a handler callback and sends responses back
  5→// via q:tool_response.
  6→//
  7→// Multiple hook instances (useAgentRpcHandler, useSimulatorRpcHandler)
  8→// may be mounted simultaneously. A module-level Set prevents duplicate
  9→// responses to the same requestId.
 10→//
 11→// Usage in RPC handler hooks:
 12→//   useWsToolRequest((method, requestId, params, respond) => {
 13→//     match(method)
 14→//       .with("getDiff", () => handleGetDiff(params, respond))
 15→//       .otherwise(() => {}); // not mine, skip
 16→//   });
 17→
 18→import { useEffect, useLayoutEffect, useRef } from "react";
 19→import { onEvent, sendToolResponse } from "@/platform/ws";
 20→import type { ToolRequestEventData } from "@shared/types/query-protocol";
 21→
 22→/**
 23→ * Callback signature for WS tool request handlers.
 24→ *
 25→ * @param method - The RPC method name (e.g., "getDiff", "browserSnapshot")
 26→ * @param requestId - Unique ID for this request (used for response routing)
 27→ * @param params - Method parameters
 28→ * @param respond - Call with result to send success response
 29→ * @param respondError - Call with error string to send error response
 30→ */
 31→export type WsToolRequestHandler = (
 32→  method: string,
 33→  requestId: string,
 34→  params: Record<string, unknown>,
 35→  respond: (result: unknown) => void,
 36→  respondError: (error: string) => void
 37→) => void;
 38→
 39→/**
 40→ * Hook that listens for tool:request events via WebSocket and dispatches
 41→ * to the provided handler. The handler decides which methods to claim.
 42→ *
 43→ * Responses are sent via q:tool_response back through the WS connection.
 44→ */
 45→export function useWsToolRequest(handler: WsToolRequestHandler): void {
 46→  const handlerRef = useRef(handler);
 47→  useLayoutEffect(() => {
 48→    handlerRef.current = handler;
 49→  });
 50→
 51→  // Track handled requestIds to prevent duplicate responses across hook instances.
 52→  // Using a module-level Set so it's shared across all instances within the same page.
 53→  const handledRef = useRef(handledRequestIds);
 54→
 55→  useEffect(() => {
 56→    const unsubscribe = onEvent((event: string, data: unknown) => {
 57→      if (event !== "tool:request") return;
 58→
 59→      const payload = data as ToolRequestEventData;
 60→      if (!payload?.requestId || !payload?.method) return;
 61→
 62→      const { requestId, method, params } = payload;
 63→
 64→      // Check if already handled by another hook instance
 65→      if (handledRef.current.has(requestId)) return;
 66→
 67→      const respond = (result: unknown) => {
 68→        if (handledRef.current.has(requestId)) return; // guard double-response
 69→        if (!sendToolResponse(requestId, result)) return; // WS send failed — let other handlers try
 70→        handledRef.current.add(requestId);
 71→        scheduleCleanup(requestId);
 72→      };
 73→
 74→      const respondError = (error: string) => {
 75→        if (handledRef.current.has(requestId)) return;
 76→        if (!sendToolResponse(requestId, undefined, error)) return;
 77→        handledRef.current.add(requestId);
 78→        scheduleCleanup(requestId);
 79→      };
 80→
 81→      handlerRef.current(method, requestId, params, respond, respondError);
 82→    });
 83→
 84→    return unsubscribe;
 85→  }, []);
 86→}
 87→
 88→// ---- Deduplication state ----
 89→
 90→/** Module-level Set of requestIds that have been responded to.
 91→ *  Shared across all hook instances within the same page lifecycle. */
 92→const handledRequestIds = new Set<string>();
 93→
 94→/** Clean up old requestIds after 60s to prevent unbounded growth. */
 95→function scheduleCleanup(requestId: string): void {
 96→  setTimeout(() => {
 97→    handledRequestIds.delete(requestId);
 98→  }, 60_000);
 99→}
100→

  1→// src/features/session/hooks/useAgentRpcHandler.ts
  2→//
  3→// Handles agent-initiated RPC requests that require frontend interaction or data access.
  4→//
  5→// Architecture:
  6→//   Agent-server → Backend → q:event tool:request → this handler
  7→//   Handler responds via: sendToolResponse (q:tool_response frame)
  8→//
  9→// Handled methods:
 10→//   exitPlanMode         — user must approve/reject an agent plan (UI interaction needed)
 11→//   askUserQuestion      — agent asks structured questions with options (UI interaction needed)
 12→//   getDiff              — agent reads workspace diff (data fetch, auto-responds)
 13→//   diffComment          — agent posts comments on diff (stored, auto-responds success)
 14→//   getTerminalOutput    — agent reads terminal output (auto-responds from node-pty)
 15→//
 16→// Pending state is stored in a Map<sessionId, PendingRequest> so multiple concurrent
 17→// agent sessions can each have their own pending request simultaneously.
 18→
 19→import { match } from "ts-pattern";
 20→import { useEffect, useLayoutEffect, useCallback, useRef, useState } from "react";
 21→import { getErrorMessage } from "@shared/lib/errors";
 22→import { sendRequest } from "@/platform/ws";
 23→import { useWsToolRequest } from "@/shared/hooks/useWsToolRequest";
 24→import { sendToolResponse } from "@/platform/ws";
 25→
 26→// ============================================================================
 27→// Types
 28→// ============================================================================
 29→
 30→export interface PlanModeRequest {
 31→  type: "exitPlanMode";
 32→  sessionId: string;
 33→  toolInput: unknown;
 34→  /** WS requestId used for q:tool_response routing */
 35→  wsRequestId: string;
 36→}
 37→
 38→export interface AskQuestionRequest {
 39→  type: "askUserQuestion";
 40→  sessionId: string;
 41→  questions: Array<{
 42→    question: string;
 43→    options: string[];
 44→    multiSelect?: boolean;
 45→  }>;
 46→  /** WS requestId used for q:tool_response routing */
 47→  wsRequestId: string;
 48→}
 49→
 50→export type PendingAgentRequest = PlanModeRequest | AskQuestionRequest;
 51→
 52→// ============================================================================
 53→// Hook
 54→// ============================================================================
 55→
 56→/**
 57→ * Context needed to auto-respond to data-fetch requests (getDiff, getTerminalOutput).
 58→ * The workspace providing this must match the session's working directory.
 59→ */
 60→export interface AgentRpcContext {
 61→  /** Map of sessionId → workspace context for that session */
 62→  sessionWorkspaces: Map<
 63→    string,
 64→    {
 65→      workspaceId: string;
 66→      workspacePath: string;
 67→      parentBranch: string;
 68→      defaultBranch: string;
 69→    }
 70→  >;
 71→}
 72→
 73→/** Response function shape used by handlers. */
 74→type RespondFn = (result: unknown) => void;
 75→
 76→/**
 77→ * Hook that handles agent-initiated RPC requests from the agent-server.
 78→ *
 79→ * Returns a Map of pending requests that require user interaction.
 80→ * The rendering layer (Chat or SessionPanel) renders appropriate UI for each.
 81→ *
 82→ * @param context - Workspace info for auto-responding to data-fetch requests
 83→ * @param onPendingChange - Called whenever the pending request map changes
 84→ */
 85→export function useAgentRpcHandler(
 86→  context: AgentRpcContext,
 87→  onPendingChange?: (pending: Map<string, PendingAgentRequest>) => void
 88→) {
 89→  // Map of sessionId → pending request awaiting user interaction
 90→  const [pendingRequests, setPendingRequests] = useState<Map<string, PendingAgentRequest>>(
 91→    () => new Map()
 92→  );
 93→
 94→  // Keep refs stable across renders so handlers don't need to be recreated
 95→  const contextRef = useRef(context);
 96→  const pendingRequestsRef = useRef(pendingRequests);
 97→
 98→  // Notify parent when pending map changes
 99→  const onPendingChangeRef = useRef(onPendingChange);
100→  const hasCommittedPendingRequestsRef = useRef(false);
101→
102→  useLayoutEffect(() => {
103→    contextRef.current = context;
104→  }, [context]);
105→
106→  useLayoutEffect(() => {
107→    pendingRequestsRef.current = pendingRequests;
108→  }, [pendingRequests]);
109→
110→  useLayoutEffect(() => {
111→    onPendingChangeRef.current = onPendingChange;
112→  }, [onPendingChange]);
113→
114→  useEffect(() => {
115→    if (!hasCommittedPendingRequestsRef.current) {
116→      hasCommittedPendingRequestsRef.current = true;
117→      return;
118→    }
119→
120→    onPendingChangeRef.current?.(pendingRequests);
121→  }, [pendingRequests]);
122→
123→  const setPendingAndNotify = useCallback(
124→    (updater: (prev: Map<string, PendingAgentRequest>) => Map<string, PendingAgentRequest>) => {
125→      setPendingRequests((prev) => updater(prev));
126→    },
127→    []
128→  );
129→
130→  // ============================================================================
131→  // exitPlanMode: store pending, wait for user approve/reject
132→  // ============================================================================
133→
134→  const handleExitPlanMode = useCallback(
135→    (params: Record<string, unknown>, wsRequestId: string) => {
136→      const sessionId = params.sessionId as string;
137→      if (!sessionId) return;
138→
139→      if (import.meta.env.DEV) {
140→        console.log("[AgentRPC] exitPlanMode pending for session:", sessionId);
141→      }
142→
143→      setPendingAndNotify((prev) => {
144→        const next = new Map(prev);
145→        next.set(sessionId, {
146→          type: "exitPlanMode",
147→          sessionId,
148→          toolInput: params.toolInput,
149→          wsRequestId,
150→        } satisfies PlanModeRequest);
151→        return next;
152→      });
153→    },
154→    [setPendingAndNotify]
155→  );
156→
157→  // ============================================================================
158→  // askUserQuestion: store pending, wait for user answers
159→  // ============================================================================
160→
161→  const handleAskUserQuestion = useCallback(
162→    (params: Record<string, unknown>, wsRequestId: string) => {
163→      const sessionId = params.sessionId as string;
164→      const questions = params.questions as AskQuestionRequest["questions"];
165→      if (!sessionId || !Array.isArray(questions)) return;
166→
167→      if (import.meta.env.DEV) {
168→        console.log(
169→          "[AgentRPC] askUserQuestion pending for session:",
170→          sessionId,
171→          questions.length,
172→          "questions"
173→        );
174→      }
175→
176→      setPendingAndNotify((prev) => {
177→        const next = new Map(prev);
178→        next.set(sessionId, {
179→          type: "askUserQuestion",
180→          sessionId,
181→          questions,
182→          wsRequestId,
183→        } satisfies AskQuestionRequest);
184→        return next;
185→      });
186→    },
187→    [setPendingAndNotify]
188→  );
189→
190→  // ============================================================================
191→  // getDiff: auto-respond using HTTP backend endpoints
192→  // ============================================================================
193→
194→  const handleGetDiff = useCallback(async (params: Record<string, unknown>, respond: RespondFn) => {
195→    const sessionId = params.sessionId as string;
196→    const file = params.file as string | undefined;
197→    const stat = params.stat as boolean | undefined;
198→
199→    const ws = contextRef.current.sessionWorkspaces.get(sessionId);
200→    if (!ws) {
201→      // No workspace context for this session — respond with a descriptive error
202→      respond({ error: `No workspace context for session ${sessionId}` });
203→      return;
204→    }
205→
206→    try {
207→      if (file) {
208→        // Single-file diff via q:request
209→        const result = await sendRequest<{
210→          diff: string;
211→          old_content?: string | null;
212→          new_content?: string | null;
213→        }>("diffFile", { workspaceId: ws.workspaceId, file });
214→        respond({ diff: result.diff });
215→      } else if (stat) {
216→        // File list with stats via q:request
217→        const result = await sendRequest<{
218→          files: Array<{ file: string; additions: number; deletions: number }>;
219→        }>("diffFiles", { workspaceId: ws.workspaceId });
220→        const statText = result.files
221→          .map((f) => `${f.file}: +${f.additions} -${f.deletions}`)
222→          .join("\n");
223→        respond({ diff: statText });
224→      } else {
225→        // All changed files list (summary, not full patch — patches can be huge)
226→        const result = await sendRequest<{
227→          files: Array<{ file: string }>;
228→        }>("diffFiles", { workspaceId: ws.workspaceId });
229→        const fileList = result.files.map((f) => f.file).join("\n");
230→        respond({ diff: fileList });
231→      }
232→    } catch (err: unknown) {
233→      console.error("[AgentRPC] getDiff failed:", err);
234→      respond({ error: getErrorMessage(err) });
235→    }
236→  }, []);
237→
238→  // ============================================================================
239→  // diffComment: auto-respond with success (comments stored for future UI)
240→  // ============================================================================
241→
242→  const handleDiffComment = useCallback(
243→    async (params: Record<string, unknown>, respond: RespondFn) => {
244→      // Comments from the agent are logged but not yet surfaced in the UI.
245→      // Respond with success so the agent can continue; a future PR adds the UI.
246→      if (import.meta.env.DEV) {
247→        console.log("[AgentRPC] diffComment received:", params.comments);
248→      }
249→      respond({ success: true });
250→    },
251→    []
252→  );
253→
254→  // ============================================================================
255→  // getTerminalOutput: auto-respond from PTY buffer
256→  // ============================================================================
257→
258→  const handleGetTerminalOutput = useCallback(
259→    async (_params: Record<string, unknown>, respond: RespondFn) => {
260→      // Terminal output is not available via buffered read. node-pty streams data
261→      // as it arrives (via q:event "pty-data" frames) and does not maintain a
262→      // scrollback buffer. There is no backend endpoint or Electron IPC handler
263→      // that can retrieve past output.
264→      //
265→      // Respond with an empty result so the agent can continue without blocking.
266→      respond({
267→        output: "",
268→        source: "none",
269→        isRunning: false,
270→        error: "Terminal output not available — PTY streams data in real-time without buffering",
271→      });
272→    },
273→    []
274→  );
275→
276→  // ============================================================================
277→  // Public API: resolve pending requests
278→  // ============================================================================
279→
280→  /**
281→   * Called by the plan approval UI when the user clicks Approve or Reject.
282→   */
283→  const resolvePlanMode = useCallback(
284→    async (sessionId: string, approved: boolean, turnId?: string) => {
285→      const pending = pendingRequestsRef.current.get(sessionId);
286→      if (!pending || pending.type !== "exitPlanMode") return;
287→
288→      setPendingAndNotify((prev) => {
289→        const next = new Map(prev);
290→        next.delete(sessionId);
291→        return next;
292→      });
293→
294→      sendToolResponse(pending.wsRequestId, { approved, turnId });
295→    },
296→    [setPendingAndNotify]
297→  );
298→
299→  /**
300→   * Called by the question UI when the user submits answers.
301→   * answers[i] is a string (single-select) or string[] (multi-select)
302→   */
303→  const resolveQuestion = useCallback(
304→    async (sessionId: string, answers: (string | string[])[]) => {
305→      const pending = pendingRequestsRef.current.get(sessionId);
306→      if (!pending || pending.type !== "askUserQuestion") return;
307→
308→      setPendingAndNotify((prev) => {
309→        const next = new Map(prev);
310→        next.delete(sessionId);
311→        return next;
312→      });
313→
314→      sendToolResponse(pending.wsRequestId, { answers });
315→    },
316→    [setPendingAndNotify]
317→  );
318→
319→  // ============================================================================
320→  // WS event listener (agent-server → backend → q:event tool:request)
321→  // ============================================================================
322→
323→  useWsToolRequest((method, requestId, params, respond, _respondError) => {
324→    if (import.meta.env.DEV) {
325→      console.log("[AgentRPC] Received request (WS):", method, "requestId:", requestId);
326→    }
327→
328→    match(method)
329→      .with("exitPlanMode", () => handleExitPlanMode(params, requestId))
330→      .with("askUserQuestion", () => handleAskUserQuestion(params, requestId))
331→      .with("getDiff", () => handleGetDiff(params, respond))
332→      .with("diffComment", () => handleDiffComment(params, respond))
333→      .with("getTerminalOutput", () => handleGetTerminalOutput(params, respond))
334→      .otherwise(() => {
335→        // Not an agent-UI method — browser RPC handler or other handler will claim it
336→      });
337→  });
338→
339→  return {
340→    pendingRequests,
341→    resolvePlanMode,
342→    resolveQuestion,
343→  };
344→}
345→

355:export const ToolRequestEventSchema = z.object({
363:export type ToolRequestEvent = z.infer<typeof ToolRequestEventSchema>;
401:  ToolRequestEventSchema,

  1→/**
  2→ * BrowserTab — native Electron BrowserView for one browser tab.
  3→ *
  4→ * Architecture: Renders a placeholder <div> and measures its bounds via
  5→ * ResizeObserver. Tells the main process to create/position a native BrowserView there.
  6→ * Unlike iframes, native BrowserViews bypass X-Frame-Options so any URL loads.
  7→ *
  8→ * All tabs stack via CSS Grid ([grid-area:1/1]) in the parent container.
  9→ * The native BrowserView floats above the DOM; overlays only show when view is hidden.
 10→ *
 11→ * Communication channels (each concern gets its own reliable path):
 12→ *   - IPC events: page-load, title-changed, url-change (push from Electron webContents)
 13→ *   - executeJavaScript: console drain + inspect event drain (pull from React)
 14→ *
 15→ * SPA navigation: pushState/replaceState patches in the init script fire
 16→ * browser:url-change events so the URL bar stays current.
 17→ */
 18→
 19→import {
 20→  useRef,
 21→  useState,
 22→  useEffect,
 23→  useLayoutEffect,
 24→  useCallback,
 25→  useImperativeHandle,
 26→  forwardRef,
 27→} from "react";
 28→import { match } from "ts-pattern";
 29→import { Button } from "@/components/ui/button";
 30→import { AlertCircle, Loader2, Globe } from "lucide-react";
 31→import { native } from "@/platform";
 32→import { BROWSER_PAGE_LOAD, BROWSER_TITLE_CHANGED, BROWSER_URL_CHANGE } from "@shared/events";
 33→import { getErrorMessage } from "@shared/lib/errors";
 34→import type { BrowserTabState, BrowserTabHandle, ConsoleLog, ElementSelectedEvent } from "../types";
 35→import { deriveTitleFromUrl } from "../types";
 36→import {
 37→  INSPECT_MODE_SETUP,
 38→  INSPECT_MODE_ENABLE,
 39→  INSPECT_MODE_DISABLE,
 40→  INSPECT_MODE_DRAIN_EVENTS,
 41→  INSPECT_MODE_VERIFY,
 42→} from "../automation/inspect-mode";
 43→import { VISUAL_EFFECTS_SETUP } from "../automation/visual-effects";
 44→
 45→/** How often to drain console logs from the webview (ms) */
 46→const CONSOLE_DRAIN_INTERVAL_MS = 1500;
 47→
 48→interface BrowserTabProps {
 49→  tab: BrowserTabState;
 50→  /** Update tab state in the parent — (tabId, updates) */
 51→  onUpdateTab: (tabId: string, updates: Partial<BrowserTabState>) => void;
 52→  /** Add a log line to the tab's console — (tabId, level, message) */
 53→  onAddLog: (tabId: string, level: ConsoleLog["level"], message: string) => void;
 54→  /** Whether this tab is the active (visible) tab */
 55→  visible: boolean;
 56→  /** Callback when user selects an element in inspect mode */
 57→  onElementSelected?: (tabId: string, event: ElementSelectedEvent) => void;
 58→  /** Which Electron window to create child BrowserViews in. Defaults to "main". */
 59→  windowLabel?: string;
 60→  /** When true, the browser container is constrained to mobile width (390px).
 61→   *  Used to trigger a bounds sync — mx-auto centering shifts x-offset
 62→   *  and ResizeObserver may not catch position-only changes. */
 63→  mobileView?: boolean;
 64→}
 65→
 66→export const BrowserTab = forwardRef<BrowserTabHandle, BrowserTabProps>(function BrowserTab(
 67→  { tab, onUpdateTab, onAddLog, visible, onElementSelected, windowLabel, mobileView },
 68→  ref
 69→) {
 70→  const placeholderRef = useRef<HTMLDivElement>(null);
 71→  // Ref = source of truth for imperative callbacks (always fresh)
 72→  const webviewCreatedRef = useRef(false);
 73→  // State = triggers effects when webview is ready
 74→  const [webviewReady, setWebviewReady] = useState(false);
 75→  // Track whether first page load completed (show overlay only during initial load)
 76→  const [hasLoaded, setHasLoaded] = useState(false);
 77→  // Brief "completing" state for loading bar finish animation (fill → fade)
 78→  const [completingLoad, setCompletingLoad] = useState(false);
 79→  const completingTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
 80→  // Guard against unmount during async webview creation
 81→  const mountedRef = useRef(true);
 82→  // Debounce bounds sync to one per animation frame
 83→  const rafRef = useRef(0);
 84→  // Track whether automation scripts (inspect mode + visual effects) have been injected
 85→  const automationInjectedRef = useRef(false);
 86→  // Ref to latest tab state — used in event handlers to read current history
 87→  const tabRef = useRef(tab);
 88→  tabRef.current = tab;
 89→  // Guard: suppress history push during back/forward navigation
 90→  // (did-navigate fires for loadURL too, which would double-push)
 91→  const suppressHistoryPushRef = useRef(false);
 92→  // Stable ref for onElementSelected callback (used by the inspect drain loop)
 93→  const onElementSelectedRef = useRef(onElementSelected);
 94→  onElementSelectedRef.current = onElementSelected;
 95→  // Track previous mobileView value to detect actual toggles (vs initial mount)
 96→  const prevMobileViewRef = useRef(mobileView);
 97→
 98→  const tabId = tab.id;
 99→  const webviewLabel = tab.webviewLabel;
100→
101→  // --- Unmount guard ---
102→  useEffect(() => {
103→    mountedRef.current = true;
104→    return () => {
105→      mountedRef.current = false;
106→      cancelAnimationFrame(rafRef.current);
107→      if (completingTimerRef.current) clearTimeout(completingTimerRef.current);
108→    };
