 22→  warn: console.warn.bind(console),
 23→  error: console.error.bind(console),
 24→  info: console.info.bind(console),
 25→};
 26→
 27→function forwardConsole(level: string, args: unknown[]): void {
 28→  try {
 29→    const serialized = args.map((arg) => {
 30→      if (typeof arg === "string") return arg;
 31→      try {
 32→        return JSON.stringify(arg);
 33→      } catch {
 34→        return String(arg);
 35→      }
 36→    });
