 43→console.log = (...args: unknown[]) => {
 44→  originalConsole.log(...args);
 45→  forwardConsole("log", args);
 46→};
 47→
 48→console.warn = (...args: unknown[]) => {
 49→  originalConsole.warn(...args);
 50→  forwardConsole("warn", args);
 51→};
 52→
 53→console.error = (...args: unknown[]) => {
 54→  originalConsole.error(...args);
 55→  forwardConsole("error", args);
 56→};
