 88→// Wrap the native methods, apply a 45s abort timeout,
 89→// and report "NotSupportedError" so the page can fall back to password auth.
 90→// ---------------------------------------------------------------------------
 91→
 92→try {
 93→  webFrame.executeJavaScript(`
 94→    (function() {
