 99→      var ABORT_DELAY_MS = 45000;
100→
101→      function createNotSupportedError() {
102→        return new DOMException(
103→          'WebAuthn is not supported in the Deus browser.',
104→          'NotSupportedError'
105→        );
106→      }
107→
108→      var origCreate = navigator.credentials.create;
109→      var origGet = navigator.credentials.get;
110→
111→      function wrapWebAuthn(originalMethod, options, args) {
112→        if (!originalMethod) return Promise.reject(createNotSupportedError());
113→
114→        var callerSignal = options && options.signal;
115→        if (callerSignal && callerSignal.aborted) {
116→          return Promise.reject(callerSignal.reason || new DOMException('Aborted', 'AbortError'));
117→        }
118→
119→        var ac = typeof AbortController === 'function' ? new AbortController() : undefined;
120→        var reqArgs = Array.prototype.slice.call(args);
121→        if (ac) reqArgs[0] = Object.assign({}, options, { signal: ac.signal });
122→
123→        var done = false;
124→        var timer;
125→
126→        return new Promise(function(resolve, reject) {
127→          timer = setTimeout(function() {
128→            if (done) return;
129→            done = true;
130→            if (ac) ac.abort();
131→            reject(new DOMException('WebAuthn timed out.', 'TimeoutError'));
132→          }, ABORT_DELAY_MS);
133→
134→          Promise.resolve().then(function() {
135→            return originalMethod.apply(navigator.credentials, reqArgs);
136→          }).then(
137→            function(v) { if (!done) { done = true; clearTimeout(timer); resolve(v); } },
138→            function(e) { if (!done) { done = true; clearTimeout(timer); reject(e); } }
139→          );
140→        });
141→      }
