143→      navigator.credentials.create = function(options) {
144→        if (options && options.publicKey) return wrapWebAuthn(origCreate, options, arguments);
145→        return origCreate ? origCreate.apply(navigator.credentials, arguments) : Promise.reject(createNotSupportedError());
146→      };
147→
148→      navigator.credentials.get = function(options) {
149→        if (options && options.publicKey) return wrapWebAuthn(origGet, options, arguments);
