199→        if (navigator.permissions.__localNetworkPolyfillApplied) return;
200→        navigator.permissions.__localNetworkPolyfillApplied = true;
201→
202→        var origQuery = navigator.permissions.query.bind(navigator.permissions);
203→        navigator.permissions.query = function(descriptor) {
204→          if (descriptor && (descriptor.name === 'local-network-access' || descriptor.name === 'local-network')) {
205→            return Promise.resolve({
206→              state: 'granted',
207→              name: descriptor.name,
208→              onchange: null,
209→              addEventListener: function() {},
210→              removeEventListener: function() {},
211→              dispatchEvent: function() { return true; }
212→            });
213→          }
214→          return origQuery(descriptor);
215→        };
216→      })();
217→    `);
218→  } catch (e) {
219→    originalConsole.error("[browser-preload] Local network polyfill failed:", e);
220→  }
